CREATE EXTENSION IF NOT EXISTS "uuid-ossp";CREATE TABLE Customers (    customer_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    customer_name VARCHAR(255) NOT NULL,    customer_email VARCHAR(255) UNIQUE NOT NULL,    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW());CREATE TABLE Agents (    agent_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    agent_name VARCHAR(255) NOT NULL,    agent_email VARCHAR(255) UNIQUE NOT NULL,    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW());CREATE TABLE TicketStatuses (    status_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    status_name VARCHAR(50) UNIQUE NOT NULL,    is_active BOOLEAN DEFAULT TRUE,    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW());INSERT INTO TicketStatuses (status_name) VALUES('New'),('Open'),('In Progress'),('Resolved'),('Closed');CREATE TABLE Tickets (    ticket_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    customer_id UUID NOT NULL,    agent_id UUID NULL,    status_id UUID NOT NULL,    subject VARCHAR(255) NOT NULL,    description TEXT NOT NULL,    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),    closed_at TIMESTAMP WITH TIME ZONE NULL,    CONSTRAINT fk_customer        FOREIGN KEY (customer_id)        REFERENCES Customers(customer_id)        ON UPDATE NO ACTION ON DELETE RESTRICT,    CONSTRAINT fk_agent        FOREIGN KEY (agent_id)        REFERENCES Agents(agent_id)        ON UPDATE NO ACTION ON DELETE SET NULL,    CONSTRAINT fk_status        FOREIGN KEY (status_id)        REFERENCES TicketStatuses(status_id)        ON UPDATE NO ACTION ON DELETE RESTRICT);CREATE TABLE TicketNotes (    note_id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    ticket_id UUID NOT NULL,    agent_id UUID NOT NULL,    note_content TEXT NOT NULL,    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),    CONSTRAINT fk_ticket        FOREIGN KEY (ticket_id)        REFERENCES Tickets(ticket_id)        ON UPDATE NO ACTION ON DELETE CASCADE,    CONSTRAINT fk_agent_note        FOREIGN KEY (agent_id)        REFERENCES Agents(agent_id)        ON UPDATE NO ACTION ON DELETE RESTRICT);